import React, { useState, useEffect } from 'react';
import { View, Button, Text } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';

const CLIENT_ID = 'your_client_id';
const AUTHORIZATION_ENDPOINT = 'https://your-auth-server.com/auth';
const TOKEN_ENDPOINT = 'https://your-auth-server.com/token';
const REDIRECT_URI = AuthSession.makeRedirectUri({ useProxy: true });

const App = () => {
  const [authCode, setAuthCode] = useState(null);
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  useEffect(() => {
    if (authCode) {
      exchangeCodeForToken(authCode);
    }
  }, [authCode]);

  const handleOAuthLogin = async () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?client_id=${CLIENT_ID}&response_type=code&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`;
    const result = await AuthSession.startAsync({ authUrl });

    if (result.type === 'success' && result.params.code) {
      setAuthCode(result.params.code);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&client_id=${CLIENT_ID}`,
      });

      const data = await response.json();
      if (data.access_token) {
        setAccessToken(data.access_token);
        setRefreshToken(data.refresh_token);
        await SecureStore.setItemAsync('refreshToken', data.refresh_token);
      }
    } catch (error) {
      console.error('Token exchange failed', error);
    }
  };

  const refreshAccessToken = async () => {
    const storedRefreshToken = await SecureStore.getItemAsync('refreshToken');
    if (!storedRefreshToken) return;

    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=refresh_token&refresh_token=${storedRefreshToken}&client_id=${CLIENT_ID}`,
      });

      const data = await response.json();
      if (data.access_token) {
        setAccessToken(data.access_token);
        await SecureStore.setItemAsync('refreshToken', data.refresh_token);
      }
    } catch (error) {
      console.error('Token refresh failed', error);
    }
  };

  return (
    <View>
      <Button title="Login with OAuth" onPress={handleOAuthLogin} />
      {accessToken ? <Text>Access Token: {accessToken}</Text> : null}
      <Button title="Refresh Token" onPress={refreshAccessToken} />
    </View>
  );
};

export default App;